import React from 'react';
import OvalButton from './Button';
import './navbar.css';

function NavBar() {
    return (
        <nav className="navbar">
            <ul className="nav-links">
                <li className="nav-item">
                    <OvalButton href="/">Accueil</OvalButton>
                </li>
                <li className="nav-item">
                    <OvalButton href="/offres">Nos offres</OvalButton>
                </li>
                <li className="nav-item">
                    <OvalButton href="/contacte">Nous contacter</OvalButton>
                </li>
                <li className="nav-item">
                    <OvalButton href="/Qui-sommes-nous">Qui sommes nous ?</OvalButton>
                </li>
            </ul>
        </nav>
    );
}

export default NavBar;
